use std::{fs::File, io::{BufWriter, Cursor, Write}, path::{Path, PathBuf}};

use base64::{Engine, engine::general_purpose::STANDARD};
use image::ImageReader;
use tracing::info;


#[test]
fn recognition_test()
{
  test_recognition().unwrap();
}

fn test_recognition() -> anyhow::Result<()>
{
  let url = std::path::Path::new("/home/phobos/Документы/000001.png");
  let base_img = ImageReader::open(url)?.decode()?;

  let mut buf: Vec<u8> = Vec::new();
  base_img.write_to(&mut Cursor::new(&mut buf), image::ImageFormat::Png)?;
  let b64 = STANDARD.encode(&buf);

  Ok(())
}

pub fn bytes_to_base64url(bytes: &[u8]) -> String
{
    format!("data:image/png;base64,{}", STANDARD.encode(bytes))
}

// Ответ БДля моделей Qwen 3.5 файл mmproj НЕ нужен, даже если вы планируете распознавать текст с картинок (OCR).В отличие от версий Qwen 2.5-VL или Qwen 3-VL, где визуальный проектор шел отдельным файлом, архитектура линейки Qwen 3.5 получила сквозную мультимодальность (Unified Vision-Language) на уровне ядра. И текстовые данные, и пиксели изображений обрабатываются одной единой нейросетью.Поэтому для работы вам понадобится только один базовый файл модели в формате .gguf.Как использовать Qwen 3.5 для распознавания текста в llama.cppПоскольку визуальные слои теперь встроены напрямую в основной файл, запускать модель нужно через стандартный аргумент -m без использования флага --mmproj.Шаг 1. Запуск сервераЗапустите llama-server, указав путь к скачанной модели Qwen 3.5 и размер контекста (модели поддерживают контекст вплоть до 256K токенов, что позволяет передавать изображения в высоком разрешении):bash./llama-server -m qwen3.5-9b-instruct-q4_k_m.gguf -c 16384 --host 127.0.0.1 --port 8080
// Используйте код с осторожностью.(Вместо 9B вы можете использовать любую другую модель из линейки, например, сверхлегкую 2B или 4B).Шаг 2. Отправка изображения на OCRДля качественного извлечения текста отправьте POST-запрос на сервер. Начиная с последних версий llama.cpp, поддерживающих архитектуру Qwen 3.5, изображение передается внутри массива image_data в формате Base64:bashcurl http://127.0.0 \
// curl --request POST --url http://10.0.0.2:8080/v1/chat/completions \
// -H "Content-Type: application/json" \
// -d '{
//   "model": "qwen3.5",
//   "messages": [
//     {
//       "role": "user",
//       "content": [
//         {"type": "text", "text": "Распознай весь текст с этого изображения. Запиши его в markdown формате, используй заголовки списки и таблицы, слова с переносами объединяй в одно слово, целиковые предложения или названия объединяй в один параграф, вместо \n используй кодировку юникода U+000A, без комментариев"},
//         {"type": "image_url", "image_url": {"url": "data:image/png;base64,"}}
//       ]
//     }
//   ],
//   "temperature": 0.0
// }'
// Используйте код с осторожностью.Важные настройки для OCR на Qwen 3.5Установите temperature строго на 0.0. Модели Qwen 3.5 невероятно сильны в распознавании документов и мелких деталей, но при повышенной температуре они могут начать "додумывать" или перефразировать слова. Нулевая температура гарантирует точное посимвольное считывание.Включайте режим рассуждения (Thinking), если он есть. Некоторые версии GGUF поддерживают переключение между Instruct и Thinking режимами. Если на картинке сложная таблица, чек с размытым шрифтом или математические формулы, включение "мышления" (повышение лимита выходных токенов для скрытых рассуждений) значительно поднимет точность OCR.Контролируйте VRAM. Хоть mmproj больше не занимает память отдельно, сама объединенная модель Qwen 3.5 требует чуть больше графической памяти при обработке картинок, чем при чистом тексте. Убедитесь, что у вас выставлен достаточный размер контекста (-c 16384 или выше), иначе большая картинка просто не поместится в сессию.Если вам потребуется помощь с конкретной командой для консоли, автоматизацией процесса на Python или вы хотите узнать, какой размер квантования лучше выбрать под вашу видеокарту, дайте знать!

